// Zusammenführen aller Preisdaten
// Input: Ergebnisse aus kaufda, rewe, aldi
// Gibt strukturierte Preisliste pro Produkt zurück

const kaufdaData = $('Kaufda Angebotssuche').all();
const reweData = $('REWE Angebote filtern').all();
const aldiData = $('Aldi Angebote laden & filtern').all();
const produkte = $('Produktliste').all();

const ergebnisse = [];

for (const produkt of produkte) {
  const p = produkt.json;
  const preise = [];

  // REWE Preise extrahieren
  const reweRes = reweData.find(r => r.json._produktName === p.name);
  if (reweRes && reweRes.json.products) {
    const reweProdukt = reweRes.json.products[0];
    if (reweProdukt) {
      preise.push({
        laden: 'REWE Oedekoven',
        preis: reweProdukt.price?.value || null,
        einheit: reweProdukt.grammage || p.einheit,
        angebot: reweProdukt.discountPrice ? true : false,
        angebotPreis: reweProdukt.discountPrice?.value || null
      });
    }
  }

  // Kaufda Preise extrahieren (aggregiert mehrere Läden)
  const kaufdaRes = kaufdaData.filter(r => r.json._produktName === p.name);
  for (const res of kaufdaRes) {
    if (res.json.offers) {
      for (const angebot of res.json.offers) {
        const ladenName = angebot.merchant?.name?.toLowerCase() || '';
        const relevanteLäden = ['edeka', 'aldi', 'dm', 'rewe'];
        const istRelevant = relevanteLäden.some(l => ladenName.includes(l));
        if (istRelevant) {
          preise.push({
            laden: angebot.merchant?.name,
            preis: angebot.price,
            einheit: angebot.unit || p.einheit,
            angebot: angebot.isOffer || false,
            angebotPreis: angebot.offerPrice || null
          });
        }
      }
    }
  }

  // Günstigsten Preis ermitteln
  const mitPreis = preise.filter(pr => pr.preis !== null);
  if (mitPreis.length === 0) {
    ergebnisse.push({
      ...p,
      preise: [],
      günstigster: null,
      zugewiesen: []
    });
    continue;
  }

  const günstigsterPreis = Math.min(...mitPreis.map(pr => pr.angebotPreis || pr.preis));
  const schwelle = günstigsterPreis * 1.20; // 20% Toleranz

  // Alle Läden innerhalb 20%-Schwelle
  const zugewiesen = mitPreis
    .filter(pr => (pr.angebotPreis || pr.preis) <= schwelle)
    .map(pr => ({
      ...pr,
      effektivPreis: pr.angebotPreis || pr.preis,
      istGünstigster: (pr.angebotPreis || pr.preis) === günstigsterPreis
    }));

  ergebnisse.push({
    ...p,
    preise: mitPreis,
    günstigsterPreis,
    zugewiesen
  });
}

return ergebnisse.map(e => ({ json: e }));

// Einkaufslisten pro Laden erstellen
const alle = $input.all();

const lädenMap = {
  'REWE Oedekoven': [],
  'EDEKA Schwindt': [],
  'Aldi Süd': [],
  'Ümit Market': [],
  'dm': []
};

// Normalisierung der Ladennamen
function normalisiereLaden(name) {
  const n = (name || '').toLowerCase();
  if (n.includes('rewe')) return 'REWE Oedekoven';
  if (n.includes('edeka')) return 'EDEKA Schwindt';
  if (n.includes('aldi')) return 'Aldi Süd';
  if (n.includes('ümit') || n.includes('umit')) return 'Ümit Market';
  if (n.includes('dm')) return 'dm';
  return null;
}

for (const item of alle) {
  const p = item.json;
  if (!p.zugewiesen || p.zugewiesen.length === 0) continue;

  for (const zuweisung of p.zugewiesen) {
    const laden = normalisiereLaden(zuweisung.laden);
    if (laden && lädenMap[laden] !== undefined) {
      lädenMap[laden].push({
        produkt: p.name,
        kategorie: p.kategorie,
        menge: p.menge,
        einheit: p.einheit,
        preis: zuweisung.effektivPreis,
        istAngebot: zuweisung.angebot,
        istGünstigster: zuweisung.istGünstigster
      });
    }
  }
}

// Output: ein Objekt pro Laden
return Object.entries(lädenMap).map(([laden, produkte]) => ({
  json: {
    laden,
    anzahlProdukte: produkte.length,
    gesamtGeschätzt: produkte.reduce((s, p) => s + (p.preis || 0), 0).toFixed(2),
    produkte: produkte.sort((a, b) => a.kategorie.localeCompare(b.kategorie))
  }
}));

// Plaintext Einkaufslisten mit Stichpunkten generieren
const läden = $input.all();
const datum = new Date().toLocaleDateString('de-DE', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

let text = `EINKAUFSLISTEN – ${datum}\n`;
text += `${'='.repeat(50)}\n\n`;

for (const item of läden) {
  const { laden, produkte, gesamtGeschätzt, anzahlProdukte } = item.json;

  text += `${laden.toUpperCase()}\n`;
  text += `${'-'.repeat(laden.length)}\n`;

  if (produkte.length === 0) {
    text += `  (keine Produkte diese Woche)\n`;
  } else {
    // Nach Kategorie gruppieren
    const nachKategorie = {};
    for (const p of produkte) {
      if (!nachKategorie[p.kategorie]) nachKategorie[p.kategorie] = [];
      nachKategorie[p.kategorie].push(p);
    }

    for (const [kat, prods] of Object.entries(nachKategorie)) {
      text += `\n  [${kat.toUpperCase()}]\n`;
      for (const p of prods) {
        // Preisanzeige: immer Vergleichspreis (pro kg/L) + optional Paketpreis
        let preisText = 'Preis unbekannt';
        if (p.comparisonDisplay) {
          // Aldi: hat comparisonDisplay direkt
          preisText = p.comparisonDisplay.trim();
          if (p.paketpreisDisplay) {
            preisText += `  (Paket: ${p.paketpreisDisplay.trim()})`;
          }
          if (p.sellingSize) {
            preisText += `  [${p.sellingSize}]`;
          }
        } else if (p.preis) {
          preisText = `${Number(p.preis).toFixed(2)} €`;
          if (p.vergleichseinheit) {
            preisText += `/${p.vergleichseinheit}`;
          }
        }

        const angebotHinweis = p.istAngebot ? ' (Angebot!)' : '';
        const günstigHinweis = p.istGünstigster ? ' ✓ günstigster' : '';
        const titelHinweis = p.angebotTitel && p.angebotTitel !== p.produkt
          ? `\n      → ${p.angebotTitel}` : '';

        text += `  • ${p.produkt} – ${preisText}${angebotHinweis}${günstigHinweis}${titelHinweis}\n`;
      }
    }

    text += `\n  Geschätzte Summe: ca. ${gesamtGeschätzt} € (${anzahlProdukte} Produkte)\n`;
  }

  text += `\n`;
}

text += `${'='.repeat(50)}\n`;
text += `✓ günstigster = bester Preis im Vergleich aller Läden\n`;
text += `Ohne ✓: liegt max. 20% über dem günstigsten Preis\n`;
text += `Preise als Vergleichspreis pro kg/L wo verfügbar\n`;

return [{ json: { text, filename: 'einkaufslisten_' + new Date().toISOString().slice(0,10) + '.txt' } }];

