// REWE Angebote filtern – passendes Angebot pro Produkt finden
const produktliste = $('Produktliste').all().map(p => p.json);
const reweResponse = $input.first();

let angebote = [];
try {
  const body = reweResponse.json;
  angebote = body.offers
    || body.data?.offers
    || (body.categories || []).flatMap(c => c.offers || [])
    || [];
} catch(e) {
  angebote = [];
}

const ergebnisse = [];

function normalize(s) {
    return s.toLowerCase()
      .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue')
      .replace(/Ä/g, 'ae').replace(/Ö/g, 'oe').replace(/Ü/g, 'ue')
      .replace(/ß/g, 'ss').replace(/[()\-\/]/g, ' ');
  }
  for (const produkt of produktliste) {
  const suchwoerter = normalize(produkt.name).split(' ').filter(w => w.length > 2);

  const treffer = angebote.filter(a => {
    const titel = normalize(a.title || a.name || '');
    return suchwoerter.some(w => titel.includes(w));
  });

  for (const t of treffer) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'REWE Oedekoven',
      angebotTitel: t.title || t.name,
      preis: t.price?.value ?? t.regularPrice ?? null,
      angebotPreis: t.offerPrice?.value ?? t.discountedPrice ?? null,
      gueltigBis: t.validUntil || t.endDate || null,
      istAngebot: true
    });
  }

  if (treffer.length === 0) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'REWE Oedekoven',
      angebotTitel: null,
      preis: null,
      angebotPreis: null,
      gueltigBis: null,
      istAngebot: false
    });
  }
}

return ergebnisse.map(e => ({ json: e }));

// EDEKA HTML parsen und Angebote extrahieren
const produktliste = $('Produktliste').all().map(p => p.json);
const html = $input.first().json.data || $input.first().json.body || '';

// Angebote aus HTML extrahieren
// EDEKA-Struktur: h2/h3 mit Produktname, dann Preis-Div, dann Beschreibungstext
const angebote = [];

// Regex für Angebot-Blöcke: Titel + Preis + Beschreibung
const angebotsBlocks = html.matchAll(
  /###?\s*Angebot:\s*([^\n]+)\n[\s\S]*?(?:\*\*Gültig ab ([^*]+)\*\*)?\s*[\s\S]*?(?:\*\*[-\d]+\s*%\*\*)?\s*([\d]+)\.\s*([\d]+)\s*([\s\S]*?)(?=###?\s*Angebot:|$)/gi
);

for (const match of angebotsBlocks) {
  const name = match[1]?.trim() || '';
  const gueltigAb = match[2]?.trim() || '';
  const euro = parseInt(match[3] || '0');
  const cent = parseInt(match[4] || '0');
  const beschreibung = match[5]?.replace(/\n+/g, ' ').trim().slice(0, 200) || '';

  // Grundpreis extrahieren (z.B. "1kg = € 3,73")
  const grundpreisMatch = beschreibung.match(/1kg\s*=\s*[€€]\s*([\d,]+)/);
  const grundpreis = grundpreisMatch
    ? parseFloat(grundpreisMatch[1].replace(',', '.'))
    : null;

  if (name && (euro > 0 || cent > 0)) {
    angebote.push({
      titel: name,
      preis: euro + cent / 100,
      grundpreis,
      beschreibung: beschreibung.slice(0, 150),
      gueltigAb,
      laden: 'EDEKA Schwindt'
    });
  }
}

// Produkte mit Angeboten matchen
const ergebnisse = [];

function normalize(s) {
    return s.toLowerCase()
      .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue')
      .replace(/Ä/g, 'ae').replace(/Ö/g, 'oe').replace(/Ü/g, 'ue')
      .replace(/ß/g, 'ss').replace(/[()\-\/]/g, ' ');
  }
  for (const produkt of produktliste) {
  const suchwoerter = normalize(produkt.name).split(' ').filter(w => w.length > 2);

  const treffer = angebote.filter(a => {
    const titel = normalize(a.titel);
    return suchwoerter.some(w => titel.includes(w));
  });

  for (const t of treffer) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'EDEKA Schwindt',
      angebotTitel: t.titel,
      preis: t.preis,
      grundpreis: t.grundpreis,
      angebotPreis: t.preis,
      beschreibung: t.beschreibung,
      gueltigAb: t.gueltigAb,
      istAngebot: true
    });
  }

  if (treffer.length === 0) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'EDEKA Schwindt',
      angebotTitel: null,
      preis: null,
      grundpreis: null,
      angebotPreis: null,
      beschreibung: null,
      gueltigAb: null,
      istAngebot: false
    });
  }
}

return ergebnisse.map(e => ({ json: e }));

// Aldi Angebote – dynamische Paginierung
// Liest totalCount aus erstem Response und holt alle Seiten automatisch
const produktliste = $('Produktliste').all().map(p => p.json);

const BASE_URL = 'https://api.aldi-sued.de/v3/product-search';
const PARAMS = new URLSearchParams({
  currency: 'EUR',
  serviceType: 'walk-in',
  categoryKey: '1588161426582123',
  servicePoint: 'B441',
  limit: '60'
});

async function fetchSeite(offset) {
  PARAMS.set('offset', String(offset));
  const res = await fetch(`${BASE_URL}?${PARAMS.toString()}`);
  if (!res.ok) throw new Error(`Aldi API Fehler: ${res.status}`);
  return res.json();
}

// Erste Seite holen um totalCount zu ermitteln
const ersteSeite = await fetchSeite(0);
const totalCount = ersteSeite?.meta?.pagination?.totalCount || 0;
let alleAngebote = ersteSeite?.data || [];

// Weitere Seiten holen falls nötig
const weitereOffsets = [];
for (let offset = 60; offset < totalCount; offset += 60) {
  weitereOffsets.push(offset);
}

for (const offset of weitereOffsets) {
  const seite = await fetchSeite(offset);
  alleAngebote = alleAngebote.concat(seite?.data || []);
}

// Produkte matchen
const ergebnisse = [];

function normalize(s) {
    return s.toLowerCase()
      .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue')
      .replace(/Ä/g, 'ae').replace(/Ö/g, 'oe').replace(/Ü/g, 'ue')
      .replace(/ß/g, 'ss').replace(/[()\-\/]/g, ' ');
  }
  for (const produkt of produktliste) {
  const suchwoerter = normalize(produkt.name).split(' ').filter(w => w.length > 2);

  const treffer = alleAngebote.filter(a => {
    const titel = normalize(a.name || '');
    const marke = normalize(a.brandName || '');
    return suchwoerter.some(w => titel.includes(w) || marke.includes(w));
  });

  for (const t of treffer) {
    const compRaw = t.price?.comparisonDisplay || '';
    const compMatch = compRaw.match(/([\d,]+)\s*[€$]/);
    const preisProEinheit = compMatch
      ? parseFloat(compMatch[1].replace(',', '.'))
      : null;

    const einheitMatch = compRaw.match(/\/\s*(\d+\s*(?:kg|l|ml|g|stk|st))/i);
    const vergleichseinheit = einheitMatch ? einheitMatch[1].trim() : null;

    const paketpreisCent = t.price?.amountRelevant ?? null;
    const paketpreisEuro = paketpreisCent !== null ? paketpreisCent / 100 : null;
    const paketpreisDisplay = t.price?.amountRelevantDisplay || null;

    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'Aldi Süd',
      angebotTitel: `${t.brandName ? t.brandName + ' ' : ''}${t.name}`,
      preis: preisProEinheit,
      vergleichseinheit,
      comparisonDisplay: compRaw,
      paketpreis: paketpreisEuro,
      paketpreisDisplay,
      sellingSize: t.sellingSize || null,
      istAngebot: true
    });
  }

  if (treffer.length === 0) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'Aldi Süd',
      angebotTitel: null,
      preis: null,
      vergleichseinheit: null,
      comparisonDisplay: null,
      paketpreis: null,
      paketpreisDisplay: null,
      sellingSize: null,
      istAngebot: false
    });
  }
}

return ergebnisse.map(e => ({ json: e }));
